proof fn phi_1_view_equal_no_marshalable_serialize_equal(a: usize, b: usize)
    requires
        a.view_equal(&b),
        !a.is_marshalable(),
        !b.is_marshalable(),
    ensures
        a.ghost_serialize() == b.ghost_serialize(),
{
    a.lemma_same_views_serialize_the_same(&b);
