proof fn phi_2_view_equal_implies_marshalable_equivalence(a: usize, b: usize)
    requires
        a.view_equal(&b),
        a.is_marshalable(),
    ensures
        b.is_marshalable(),
{
    a.lemma_same_views_serialize_the_same(&b);
}

proof fn phi_4_usize_over_u64max_serialize_unconstrained(a: usize, b: usize)
    requires
        *a as int > u64::MAX,
        *b as int > u64::MAX,
        a@ == b@,
    ensures
        a.ghost_serialize() == b.ghost_serialize(),
{
    a.lemma_same_views_serialize_the_same(&b);
}
